var is Function-Scoped (or Globally Scop:
var هو نطاق الوظيفة (أو النطاق العالمي):
يمكن الوصول إلى المتغير المعلن باستخدام var خلال الوظيفة التي تم الإعلان عنه فيها بالكامل. إذا تم الإعلان عنها خارج أي دالة، فإنها تصبح متغيرًا عامًا. بشكل حاسم، يتجاهل var نطاقات الكتلة (مثل عبارات if، وحلقات for، وحلقات while، وما إلى ذلك).

مثال (فار):

وظيفة تحية () {
    إذا (صحيح) {
        var message = "مرحبًا من var!"; // مُعلن داخل كتلة if
    }
    console.log(message); // الإخراج: "مرحبًا من فار!"
    // يمكن الوصول إلى "الرسالة" هنا لأن var ذو نطاق وظيفي.
}
تحية();

// console.log(message); // سيؤدي هذا إلى ظهور خطأ مرجعي، لأن "الرسالة" ليست عامة.

لـ (var i = 0; i < 3; i++) {
    // ...
}
console.log(i); // الإخراج: 3 (يمكن الوصول إلى i خارج حلقة for)

let is Block-Scoped:\nA variable declare:
دعونا يكون نطاق الكتلة:
المتغير المعلن باستخدام Let لا يمكن الوصول إليه إلا داخل الكتلة ({}) حيث تم الإعلان عنه. يتضمن ذلك عبارات if، وحلقات for، وحلقات while، وأي كتلة تعليمات برمجية أخرى. يساعد هذا في منع عمليات الكتابة فوق المتغيرات غير المقصودة ويجعل التعليمات البرمجية الخاصة بك أكثر قابلية للتنبؤ بها.

مثال (دع):

وظيفة تحية حديثة () {
    إذا (صحيح) {
        Let message = "مرحبًا من Let!"; // مُعلن داخل كتلة if
        console.log(message); // الإخراج: "مرحبًا من Let!" (يمكن الوصول إليها هنا)
    }
    // console.log(message); // سيؤدي هذا إلى ظهور خطأ مرجعي،
    // حيث أن "الرسالة" يتم تحديد نطاقها في عبارة if.
}
